SELECT u.* FROM user u
INNER JOIN follow f ON u.id = f.follower_id
WHERE f.following_id = #{userId}
AND u.status = 1

    AND f.follower_id > #{cursor}

ORDER BY f.follower_id ASC
LIMIT #{size}

